return [{ json: {
  alert_source: 'Datadog',
  alert_triggered_at: '2026-07-14T08:43:00Z',
  service: 'ProjectFlow API',
  spikes: [
    { error_type: 'TimeoutError', error_message: 'pg.query: statement timeout after 30000ms', count_last_5min: 847, count_baseline: 12, endpoints: ['/api/v2/dashboard', '/api/v2/workspaces/:id/projects'], severity: 'critical' },
    { error_type: 'TypeError', error_message: "Cannot read properties of undefined (reading 'customFields')", count_last_5min: 203, count_baseline: 0, endpoints: ['/api/v2/projects/:id/export/csv'], severity: 'high' },
    { error_type: 'AuthError', error_message: 'JWT: token expired', count_last_5min: 34, count_baseline: 28, endpoints: ['/api/v2/auth/refresh'], severity: 'low' }
  ],
  deployment_context: 'v2.4.1 deployed 2026-07-12T14:00Z. No deployments since.'
} }];

const d = $input.first().json;
const spikesText = d.spikes.map(s => `  [${s.severity.toUpperCase()}] ${s.error_type}: ${s.error_message}
  Count (5min): ${s.count_last_5min} vs baseline ${s.count_baseline} (${s.count_baseline === 0 ? 'NEW' : Math.round(s.count_last_5min/s.count_baseline)+'x'}x spike)
  Endpoints: ${s.endpoints.join(', ')}`).join('

');
const system = `You are a staff engineer explaining production incidents to non-technical PMs and stakeholders. You translate error log data into plain English: what is broken, who is affected, what they cannot do, and what the business impact likely is. You are concise, specific, and factual. Return ONLY valid JSON.`;
const user = `Translate this error spike report for a PM/stakeholder audience.
Service: ${d.service}
Alert triggered: ${d.alert_triggered_at}
Deployment context: ${d.deployment_context}

Error spikes:
${spikesText}

Return JSON:
{
  "executive_summary": "string — 2-3 sentences in plain English: what is broken, how many users are affected, what they cannot do",
  "translated_errors": [
    {
      "technical_error": "string",
      "plain_english": "string — what this means for a user, not a developer",
      "user_impact": "string — what users cannot do because of this error",
      "affected_feature": "string",
      "severity": "critical|high|medium|low",
      "is_regression": true
    }
  ],
  "recommended_action": "string — what the PM should do or communicate right now",
  "estimated_user_impact_pct": "string — rough estimate of percentage of active users affected"
}`;
return [{ json: { data: d, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Translation Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.translated_errors || !Array.isArray(parsed.translated_errors)) return [{ json: { _error: true, reason: 'Missing translated_errors' } }];
return [{ json: { _error: false, result: parsed, meta: { service: upstream.data.service, alert_at: upstream.data.alert_triggered_at, spike_count: upstream.data.spikes.length, generated_at: new Date().toISOString() } } }];

const { result: r, meta: m } = $input.first().json;
const lines = (r.translated_errors||[]).map(e => `  [${e.severity.toUpperCase()}${e.is_regression?' REGRESSION':''}] ${e.affected_feature}\n  What users see: ${e.plain_english}\n  What they cannot do: ${e.user_impact}`).join('\n\n');
const report = [
  `ERROR SPIKE REPORT: ${m.service}`,
  `Alert at: ${m.alert_at} | Generated: ${m.generated_at}`,
  ``,
  `SUMMARY: ${r.executive_summary}`,
  ``,
  `ESTIMATED USER IMPACT: ${r.estimated_user_impact_pct}`,
  ``,
  `WHAT IS BROKEN:`,
  lines,
  ``,
  `RECOMMENDED ACTION: ${r.recommended_action}`,
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
